import{_ as e,c as a,o,V as t}from"./chunks/framework.CwimN0wr.js";const g=JSON.parse('{"title":"Schema Proxy","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/mixins/mixins.schema-proxy.md","filePath":"api/core/mixins/mixins.schema-proxy.md"}'),s={name:"api/core/mixins/mixins.schema-proxy.md"},r=t('<h1 id="schema-proxy" tabindex="-1">Schema Proxy <a class="header-anchor" href="#schema-proxy" aria-label="Permalink to &quot;Schema Proxy&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>schemaProxy</code> mixin provides a component with methods to load and access a <a href="https://json-schema.org/" target="_blank" rel="noreferrer">JSON Schema</a> object. The schema can be supplied in three ways: as an inline JSON string (<code>schemaJson</code>), as an async factory function (<code>schemaFunction</code>), or by name as a resource file that will be fetched at runtime. It also supports filtering which schema properties are exposed.</p><p>Pending load requests are cached via a querable promise and only re-initiated when the resolved schema name changes.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { service, schemaProxy } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@kalisio/kdk/core/client&#39;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  mixins: [service, schemaProxy],</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><table><thead><tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>schemaJson</code></td><td><code>String</code></td><td><code>&#39;&#39;</code></td><td>An inline JSON string representing the schema. Takes priority over <code>schemaFunction</code> and resource loading.</td></tr><tr><td><code>schemaFunction</code></td><td><code>Function</code></td><td><code>null</code></td><td>An async function that returns a schema object. Used when <code>schemaJson</code> is not set.</td></tr><tr><td><code>schemaProperties</code></td><td><code>String | Array</code></td><td><code>[]</code></td><td>A comma-separated string or array of property names to keep in the schema. All other properties are removed.</td></tr></tbody></table><h2 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h2><table><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>schema</code></td><td><code>Object | null</code></td><td><code>null</code></td><td>The currently loaded (and optionally filtered) JSON Schema object.</td></tr></tbody></table><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="getschema" tabindex="-1"><code>getSchema()</code> <a class="header-anchor" href="#getschema" aria-label="Permalink to &quot;`getSchema()`&quot;">​</a></h3><p>Returns the currently loaded schema.</p><ul><li><strong>Returns:</strong> <code>Object | null</code></li></ul><h3 id="getschemaid" tabindex="-1"><code>getSchemaId()</code> <a class="header-anchor" href="#getschemaid" aria-label="Permalink to &quot;`getSchemaId()`&quot;">​</a></h3><p>Returns the <code>$id</code> field of the currently loaded schema.</p><ul><li><strong>Returns:</strong> <code>string</code> — <code>schema.$id</code>, or an empty string if no schema is loaded.</li></ul><h3 id="filterschema" tabindex="-1"><code>filterSchema()</code> <a class="header-anchor" href="#filterschema" aria-label="Permalink to &quot;`filterSchema()`&quot;">​</a></h3><p>Filters <code>schema.properties</code> to keep only the entries listed in <code>schemaProperties</code>. Also updates <code>schema.$id</code> with a suffix derived from the filter so that a filtered schema is not confused with the full one, and intersects <code>schema.required</code> accordingly.</p><p>This method is called automatically after every successful schema load.</p><h3 id="loadschemafromresource-schemaname" tabindex="-1"><code>loadSchemaFromResource(schemaName)</code> <a class="header-anchor" href="#loadschemafromresource-schemaname" aria-label="Permalink to &quot;`loadSchemaFromResource(schemaName)`&quot;">​</a></h3><p>Fetches a schema JSON file by name using the KDK schema loader and applies property filtering.</p><ul><li><strong>Parameters:</strong><ul><li><code>schemaName</code> <em>(string)</em>: The schema resource name (e.g. <code>&#39;users.create&#39;</code>).</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — the loaded and filtered schema.</li><li><strong>Emits:</strong> global <code>error</code> event on failure.</li></ul><h3 id="loadschemafromjson-json" tabindex="-1"><code>loadSchemaFromJson(json)</code> <a class="header-anchor" href="#loadschemafromjson-json" aria-label="Permalink to &quot;`loadSchemaFromJson(json)`&quot;">​</a></h3><p>Parses the given JSON string as a schema and applies property filtering.</p><ul><li><strong>Parameters:</strong><ul><li><code>json</code> <em>(string)</em>: A valid JSON string representing the schema.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — the parsed and filtered schema.</li><li><strong>Emits:</strong> global <code>error</code> event on failure.</li></ul><h3 id="loadschemafromfunction-f" tabindex="-1"><code>loadSchemaFromFunction(f)</code> <a class="header-anchor" href="#loadschemafromfunction-f" aria-label="Permalink to &quot;`loadSchemaFromFunction(f)`&quot;">​</a></h3><p>Calls the provided async function to obtain a schema and applies property filtering.</p><ul><li><strong>Parameters:</strong><ul><li><code>f</code> <em>(Function)</em>: An async function that resolves to a schema object.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — the resolved and filtered schema.</li><li><strong>Emits:</strong> global <code>error</code> event on failure.</li></ul><h3 id="loadschema-schemaname" tabindex="-1"><code>loadSchema(schemaName)</code> <a class="header-anchor" href="#loadschema-schemaname" aria-label="Permalink to &quot;`loadSchema(schemaName)`&quot;">​</a></h3><p>Main entry point for schema loading. Dispatches to <code>loadSchemaFromJson</code>, <code>loadSchemaFromFunction</code>, or <code>loadSchemaFromResource</code> based on which props are set. The resulting promise is cached and reused as long as the schema name has not changed.</p><ul><li><strong>Parameters:</strong><ul><li><code>schemaName</code> <em>(string)</em>: The target schema resource name, used when neither <code>schemaJson</code> nor <code>schemaFunction</code> are set.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — the loaded schema.</li></ul><p><strong>Priority order:</strong></p><ol><li><code>schemaJson</code> prop (inline JSON string)</li><li><code>schemaFunction</code> prop (async factory)</li><li><code>schemaName</code> argument (resource file)</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Schema names for service resources follow the pattern <code>&lt;service&gt;.&lt;operation&gt;[-perspective]</code> (e.g. <code>users.create</code>, <code>users.update-profile</code>). The <code>.json</code> extension is appended automatically.</p></div>',35),c=[r];function i(d,n,l,h,m,p){return o(),a("div",null,c)}const f=e(s,[["render",i]]);export{g as __pageData,f as default};
